declare interface RGB {    r: number;    g: number;    b: number;}declare interface RGBA extends RGB {    a: number;}declare interface HSL {    h: number;    s: number;    l: number;}declare interface ButtonColor {    bgColor: string,    hoverBgColor: string,    disabledBgColor: string,    textColor: string,    hoverTextColor: string,    disabledTextColor: string}